/*    _   __   ___    _   ____    _    _        _____    ___     _____     | | / /  / _ \  | | |  _ \  | |  | |      |___  |  / _ \   |  ___|     | |/ /  | |_| | | | | |_| | |  \/  |         / /  | |_| |  | |__     |   /   |  _  | | | |  _ /  | |\/| |        / /   |  _  |  |  __|     | |\ \  | | | | | | | | \ \ | |  | |       / /__  | | | |  | |     |_| \_\ |_| |_| |_| |_| |_| |_|  |_|      |_____| |_| |_|  |_|      */#include<bits/stdc++.h>typedef long long ll;using namespace std;#ifndef ONLINE_JUDGE#include "debug.cpp"#else#define kar(...)#endif#define pb push_back#define F first#define S second#define all(x) x.begin(),x.end()#define rall(x) x.rbegin(),x.rend()#define int ll#define endl '\n' const int N = 3e5 + 30, mod = 1e9 + 7, INF = 1e18 + 10; void Solve() {    int even = 0, odd = 0;    vector<int> v(26);     for (auto& x : v) {        cin >> x;        even += x / 2;        odd += x % 2;    }     int l = 0, r = 1e10, ans = 0;      auto calc = [&](int x) {        int p = x;        p -= (p % 2 == 0);        p /= 2;        p *= (p + 1);        if (x % 2 == 0) {            p += x / 2;        }         if (p > even) return false;        int ev = even;        ev -= p;        int nw_odd = odd + ev * 2;        int imp = (x + 1) / 2;        return imp <= nw_odd;    };     while (l <= r) {        int md = l + (r - l) / 2;        if (calc(md)) {            ans = md;            l = md + 1;        } else r = md - 1;    }    cout << ans << endl;} int32_t main() {#ifndef ONLINE_JUDGE    freopen("input.txt", "r",stdin);    freopen("output.txt", "w",stdout);#endif    freopen("cube.in", "r",stdin);    ios::sync_with_stdio(0), cin.tie(0);    int Test_case = 1;    cin >> Test_case;    while (Test_case--) Solve();}